class Solution(object):
    def areNumbersAscending(self, s):
        tokens = s.split()
        numbers = [int(t) for t in tokens if t.isdigit()]
        for i in range(1, len(numbers)):
            if numbers[i] <= numbers[i-1]:
                return False
        return True
